src/main/java/com/fasterxml/jackson/core.fixed_method:
protected final void _verifyRelease(byte[] toRelease, byte[] src) {
    if (toRelease == null || src == null) {
        throw new IllegalArgumentException("Buffers cannot be null");
    }
    if (toRelease != src) {
        if (toRelease.length < src.length) {
            throw new IllegalArgumentException("Buffer cannot be smaller than original");
        } else if (toRelease.length > src.length) {
            throw new IllegalArgumentException("Buffer cannot be larger than original");
        }
    }
}

